"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[7831],{8097(e){e.exports=JSON.parse('{"slug":"milky1","title":"Milky Way in Sai Kung (Untracked)","date":"2025-09","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/milky1-thumb.jpg","image":"/img/gallery/_gen/milky1-full.jpg","aspect":1.3819987959060807,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/milky1.jpg","source":"@site/gallery/milky1.mdx","sourceFilePath":"gallery/milky1.mdx","_content":"\\nFirst time trying the Milky Way. Stock EOS R8, cheap RF 24-50 f4.5-6.3 IS STM @ 24mm f4.5, 100x 8s ISO 3200. Processed in Siril & Darktable.\\n\\nTook darks/biases/flats but didn\'t use it because lens vignetting and distortion are so bad that the four corners are completely black. I need to load the camera raw into darktable for lens correction and directly use the processed linear images for stacking, so I didn\'t apply the calibration frames. Bortle 5 but closer to bortle 6 due to the extremely bright blue fishing boat lights nearby, I can\'t even see the milky way from the raw camera frames. But nevertheless it is a good first try."}')}}]);